(5, '算法竞赛实验室', 'LAB-MA-001', 5, '专注于 ACM/ICPC、蓝桥杯等算法竞赛。', '钱峰', '理学院B301', 'algo_lab@school.edu.cn', 'C++、算法、数据结构', 20, 0, 1, '2020-09', 'ACM 区域赛金奖', '[{"name":"郑毅","major":"数学","achievement":"入职字节跳动"}]', '算法与数学竞赛训练中心。', '钱峰、孙博', '钱教授', 1);
